package CWT;

public class JavaOperaters {

	public static void main(String[] args) {
		// TODO Auto-generated method stub

		
		int a = 10 ;
		int b = 7;
		
		System.out.println(a+b);
		System.out.println(a-b);
		System.out.println(a*b);
		System.out.println(a/b);
		System.out.println(a%b);
		
	}

}
